{
  "name": "mcp-server-sqlite-sandbox",
  "version": "1.0.0",
  "description": "Sandboxed SQLite MCP server",
  "type": "module",
  "main": "index.js",
  "bin": {
    "mcp-server-sqlite": "./index.js"
  },
  "dependencies": {
    "@modelcontextprotocol/server-sqlite": "^0.6.2"
  }
}

import sys
import sqlite3
import os
from mcp.server.fastmcp import FastMCP

DB_PATH = os.getenv("SQLITE_DB_PATH", "/workspace/db.sqlite")

mcp = FastMCP("sqlite-sandbox")

def get_connection():
    db_dir = os.path.dirname(DB_PATH)
    if db_dir and not os.path.exists(db_dir):
        try:
            os.makedirs(db_dir, exist_ok=True)
        except Exception:
            pass
    return sqlite3.connect(DB_PATH)

@mcp.tool()
def read_query(sql: str) -> str:
    """Execute a read-only SELECT query on the SQLite database and return results as formatted text."""
    sql_stripped = sql.strip().upper()
    if not sql_stripped.startswith("SELECT") and not sql_stripped.startswith("WITH") and not sql_stripped.startswith("PRAGMA"):
        return "Error: read_query only allows SELECT, WITH, or PRAGMA statements. Use write_query for modifications."

    try:
        with get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(sql)
            columns = [col[0] for col in cursor.description] if cursor.description else []
            rows = cursor.fetchall()
            if not rows:
                return "Query executed successfully. 0 rows returned."

            # Format as a simple readable table
            header = " | ".join(columns)
            sep = "-+-".join(["-" * len(c) for c in columns])
            body = "\n".join(" | ".join(str(val) for val in row) for row in rows)
            return f"{header}\n{sep}\n{body}"
    except Exception as e:
        return f"Error executing read query: {e}"

@mcp.tool()
def write_query(sql: str) -> str:
    """Execute a modifying query (INSERT, UPDATE, DELETE, CREATE, DROP) on the SQLite database."""
    try:
        with get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(sql)
            conn.commit()
            changes = conn.total_changes
            return f"Query executed successfully. Total changes: {changes} rows modified."
    except Exception as e:
        return f"Error executing write query: {e}"

@mcp.tool()
def list_tables() -> str:
    """List all tables available in the database schema."""
    try:
        with get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute("SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%';")
            tables = [row[0] for row in cursor.fetchall()]
            if not tables:
                return "No tables found in the database."
            return "Tables:\n" + "\n".join(f"- {t}" for t in tables)
    except Exception as e:
        return f"Error listing tables: {e}"

@mcp.tool()
def describe_table(table_name: str) -> str:
    """Describe the schema (columns, types, nullability, defaults) for a specific table."""
    try:
        with get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(f"PRAGMA table_info({table_name});")
            rows = cursor.fetchall()
            if not rows:
                return f"Table '{table_name}' does not exist or has no columns."
            header = "Column | Type | NotNull | Default | PK"
            sep = "-------+------+---------+---------+---"
            body = []
            for row in rows:
                body.append(f"{row[1]} | {row[2]} | {'Yes' if row[3] else 'No'} | {row[4] or 'NULL'} | {'Yes' if row[5] else 'No'}")
            return f"Schema for table '{table_name}':\n\n{header}\n{sep}\n" + "\n".join(body)
    except Exception as e:
        return f"Error describing table: {e}"

if __name__ == "__main__":
    mcp.run()

from mcp.server.fastmcp import FastMCP
import subprocess
import os

mcp = FastMCP("shell-sandbox")

@mcp.tool()
def run_command(command: str) -> str:
    """Execute a bash shell command inside the isolated container sandbox and return stdout/stderr."""
    # Ensure commands run inside the mounted workspace directory if it exists, or /tmp
    cwd = "/workspace" if os.path.exists("/workspace") else "/tmp"

    try:
        res = subprocess.run(
            ["/bin/bash", "-c", command],
            capture_output=True,
            text=True,
            timeout=60,
            cwd=cwd
        )
        out = ""
        if res.stdout:
            out += f"STDOUT:\n{res.stdout}\n"
        if res.stderr:
            out += f"STDERR:\n{res.stderr}\n"
        if not res.stdout and not res.stderr:
            out += "Command produced no output.\n"
        out += f"Exit Code: {res.returncode}"
        return out
    except subprocess.TimeoutExpired:
        return "Error: Command execution timed out after 60 seconds."
    except Exception as e:
        return f"Error executing command: {e}"

if __name__ == "__main__":
    mcp.run()

{
  description = "mcp-box: Turnkey immutable Linux container sandboxes for MCP servers";

  inputs = {
    nixpkgs.url = "github:nixos/nixpkgs/nixos-unstable";
    flake-utils.url = "github:numtide/flake-utils";
  };

  outputs = { self, nixpkgs, flake-utils }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = import nixpkgs { inherit system; };

        # Helper package to wrap the SQLite MCP script
        sqlite-server-pkg = pkgs.stdenv.mkDerivation {
          name = "mcp-server-sqlite-pkg";
          src = ./src/sqlite;
          dontBuild = true;
          installPhase = ''
            mkdir -p $out/app
            cp server.py $out/app/server.py
          '';
        };

        # Helper package to wrap the Shell MCP script
        shell-server-pkg = pkgs.stdenv.mkDerivation {
          name = "mcp-server-shell-pkg";
          src = ./src/shell;
          dontBuild = true;
          installPhase = ''
            mkdir -p $out/app
            cp server.py $out/app/server.py
          '';
        };

        # Define OCI Streamed Layered Images
        images = {
          sqlite = pkgs.dockerTools.streamLayeredImage {
            name = "mcp-box-sqlite";
            tag = "latest";
            contents = [
              (pkgs.python3.withPackages (ps: [ ps.fastmcp ]))
              pkgs.sqlite
              pkgs.bash
              pkgs.coreutils
              sqlite-server-pkg
            ];
            config = {
              Cmd = [ "python3" "/app/server.py" ];
              Env = [
                "PATH=${pkgs.lib.makeBinPath [
                  (pkgs.python3.withPackages (ps: [ ps.fastmcp ]))
                  pkgs.sqlite
                  pkgs.bash
                  pkgs.coreutils
                ]}"
                "SQLITE_DB_PATH=/workspace/db.sqlite"
              ];
              WorkingDir = "/workspace";
            };
          };

          shell = pkgs.dockerTools.streamLayeredImage {
            name = "mcp-box-shell";
            tag = "latest";
            contents = [
              (pkgs.python3.withPackages (ps: [ ps.fastmcp ]))
              pkgs.bashInteractive
              pkgs.coreutils
              pkgs.ripgrep
              pkgs.fd
              pkgs.git
              pkgs.curl
              pkgs.jq
              pkgs.sqlite
              pkgs.tar
              pkgs.gzip
              shell-server-pkg
            ];
            config = {
              Cmd = [ "python3" "/app/server.py" ];
              Env = [
                "PATH=${pkgs.lib.makeBinPath [
                  (pkgs.python3.withPackages (ps: [ ps.fastmcp ]))
                  pkgs.bashInteractive
                  pkgs.coreutils
                  pkgs.ripgrep
                  pkgs.fd
                  pkgs.git
                  pkgs.curl
                  pkgs.jq
                  pkgs.sqlite
                  pkgs.tar
                  pkgs.gzip
                ]}"
              ];
              WorkingDir = "/workspace";
            };
          };

          filesystem = pkgs.dockerTools.streamLayeredImage {
            name = "mcp-box-filesystem";
            tag = "latest";
            contents = [
              pkgs.mcp-server-filesystem
              pkgs.ripgrep
              pkgs.fd
              pkgs.git
              pkgs.bash
              pkgs.coreutils
            ];
            config = {
              Cmd = [ "mcp-server-filesystem" "/workspace" ];
              Env = [
                "PATH=${pkgs.lib.makeBinPath [
                  pkgs.mcp-server-filesystem
                  pkgs.ripgrep
                  pkgs.fd
                  pkgs.git
                  pkgs.bash
                  pkgs.coreutils
                ]}"
              ];
              WorkingDir = "/workspace";
            };
          };

          fetch = pkgs.dockerTools.streamLayeredImage {
            name = "mcp-box-fetch";
            tag = "latest";
            contents = [
              pkgs.mcp-server-fetch
              pkgs.bash
              pkgs.coreutils
              pkgs.curl
            ];
            config = {
              Cmd = [ "mcp-server-fetch" ];
              Env = [
                "PATH=${pkgs.lib.makeBinPath [
                  pkgs.mcp-server-fetch
                  pkgs.bash
                  pkgs.coreutils
                  pkgs.curl
                ]}"
              ];
              WorkingDir = "/workspace";
            };
          };
        };

        # CLI Wrapper Script Package
        mcp-box-cli = pkgs.writeShellApplication {
          name = "mcp-box";
          runtimeInputs = [ pkgs.bash pkgs.docker pkgs.git ];
          text = builtins.readFile ./mcp-box;
        };

      in
      {
        inherit images;
        packages = {
          default = mcp-box-cli;
          mcp-box = mcp-box-cli;
        } // images;
      }
    );
}

# A traditional Nix fallback for non-flake or legacy nix-build invocations.
